mapper.select:
SELECT r.*, p.real_name, p.gender, p.birthdate, d.dept_name, e.realname as doctor_name, rl.regist_name,
       mr.diagnosis, mr.record_status
FROM register r
JOIN patient p ON r.patient_id = p.id
JOIN department d ON r.deptment_id = d.id
JOIN employee e ON r.employee_id = e.id
JOIN regist_level rl ON r.regist_level_id = rl.id
LEFT JOIN medical_record mr ON r.id = mr.register_id
WHERE r.patient_id = #{patientId}
AND r.visit_date >= #{startDate}
AND r.visit_date <= #{endDate}
AND r.visit_state = #{visitState}
ORDER BY r.visit_date DESC

SELECT COUNT(*)
FROM register r
WHERE r.deptment_id = #{deptId}
  AND r.employee_id = #{doctorId}
  AND r.visit_date = #{visitDate}
  AND (r.noon = #{noon}
       OR (#{noon} = 'MORNING' AND r.noon = 'AM')
       OR (#{noon} = 'AFTERNOON' AND r.noon = 'PM')
       OR (#{noon} = 'AM' AND r.noon = 'MORNING')
       OR (#{noon} = 'PM' AND r.noon = 'AFTERNOON'))
  AND r.queue_no < #{queueNo}
  AND r.visit_state IN ('REGISTERED', 'CHECKED_IN', 'DOCTOR_RECEIVED')
